const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    try {
        // Get the bucket and key from the S3 event
        const bucket = event.Records[0].s3.bucket.name;
        const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
        
        // Read the file from S3
        const file = await s3.getObject({ Bucket: bucket, Key: key }).promise();
        
        // Process the file (example: convert to uppercase)
        const processedData = file.Body.toString('utf-8').toUpperCase();
        
        // Create output key using original filename
        const outputKey = `processed-${key}`;
        
        // Save processed file to S3
        await s3.putObject({
            Bucket: bucket,
            Key: outputKey,
            Body: processedData,
            ContentType: 'text/plain'
        }).promise();
        
        console.log(`Successfully processed and saved: ${outputKey}`);
        
        return {
            statusCode: 200,
            body: JSON.stringify({
                message: 'File processed successfully',
                input: key,
                output: outputKey
            })
        };
    } catch (error) {
        console.error('Error processing file:', error);
        throw error;
    }
};